INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"how-are-htmlelementinnertext-and-nodetextcontent-different"', '"Logic"', '"vanilla"', '{"demo.css": "div {\r\n  margin: 1rem;\r\n}\r\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      How can I execute an event handler at most once?\r\n    </h1>\r\n    <p id=\"greeting\">Hi there! My name is <strong>Bubbles</strong>.</p>\r\n    <div class=\"card\">\r\n      <style>\r\n        p {\r\n          color: red;\r\n        }\r\n        strong {\r\n          text-transform: uppercase;\r\n        }\r\n        small {\r\n          display: none;\r\n        }\r\n      </style>\r\n      <p>Hi there!<br />My name is <strong>Bubbles</strong>.</p>\r\n      <small>And I''m a <strong>dog</strong>.</small>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const greeting = document.getElementById(''greeting'');\n\ngreeting.innerText; // \"Hi there! My name is Bubbles.\"\ngreeting.textContent; // \"Hi there! My name is Bubbles.\"\n\ngreeting.innerText = ''Hello!''; // <p id=\"greeting\">Hello!</p>\ngreeting.textContent = ''Hi!''; // <p id=\"greeting\">Hi!</p>\n\nconst card = document.querySelector(''.card'');\n\ncard.innerText;\n/*\n\"Hi there!\nMy name is BUBBLES.\"\n*/\n\ncard.textContent;\n/*\n\"\n\n    p { color: red; }\n    strong { text-transform: uppercase; }\n    small { display: none; }\n\n  Hi   there!My name is Bubbles.\n  And I''m a dog.\n\"\n*/\n"}', '{}', '{"original_path": "Vanilla/Logic/Browser/how-are-htmlelementinnertext-and-nodetextcontent-different"}'), ('"how-can-i-detect-if-caps-lock-is-on-with-javascript"', '"Logic"', '"vanilla"', '{"demo.css": "div {\r\n  margin: 1rem;\r\n}\r\n\r\nspan {\r\n  margin: 1rem;\r\n}\r\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\n    <link rel=\"stylesheet\" href=\"style.css\" />\n    <title>Static Template</title>\n  </head>\n  <body>\n    <form>\n      <label for=\"username\">Username:</label>\n      <input id=\"username\" name=\"username\" />\n\n      <label for=\"password\">Password:</label>\n      <input id=\"password\" name=\"password\" type=\"password\" />\n      <span id=\"password-message\" style=\"display: none;\">Caps Lock is on</span>\n    </form>\n    <div>\n      Oftentimes, especially when creating password inputs, you need to check if\n      the Caps Lock key is on and inform the user. You can do that using the\n      <a\n        href=\"https://developer.mozilla.org/en-US/docs/Web/API/KeyboardEvent/getModifierState\"\n        >KeyboardEvent.getModifierState()</a\n      >\n      method with a value of `''CapsLock''`. This means that you have to listen\n      for a keyboard event on an element in order to check the state of the Caps\n      Lock key:\n    </div>\n    <div>\n      As you can see from the above example, the `''keyup''` event is used on our\n      element of choice to then call `KeyboardEvent.getModifierState()` and\n      determine the state of the `''CapsLock''` key. `''keydown''` and `''keypress''`\n      might also work. However, after testing on multiple devices, it seems that\n      using `''keyup''` is the preferred method as it works better across\n      different OSes and browsers.\n    </div>\n  </body>\n  <script src=\"script.js\"></script>\n</html>\n", "demo.js": "const el = document.getElementById(\"password\");\r\nconst msg = document.getElementById(\"password-message\");\r\n\r\nel.addEventListener(\"keyup\", (e) => {\r\n  msg.style = e.getModifierState(\"CapsLock\")\r\n    ? \"display: block\"\r\n    : \"display: none\";\r\n});\r\n"}', '{}', '{"original_path": "Vanilla/Logic/Browser/how-can-i-detect-if-caps-lock-is-on-with-javascript"}'), ('"how-can-i-execute-an-event-handler-at-most-once"', '"Logic"', '"vanilla"', '{"demo.css": "div {\r\n  margin: 1rem;\r\n}\r\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      How can I execute an event handler at most once?\r\n    </h1>\r\n    <button id=\"my-btn\">Click me!</button>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/* original jquery api.\n$(\"#my-btn\").one(\"click\", () => {\n  console.log(\"Hello!\"); // ''Hello!'' will only be logged on the first click\n});\n*/\n\nconst listenOnce = (el, evt, fn) => {\n  let fired = false;\n  el.addEventListener(evt, (e) => {\n    if (!fired) fn(e);\n    fired = true;\n  });\n};\n\nlistenOnce(document.getElementById(\"my-btn\"), \"click\", () =>\n  console.log(\"Hello!\")\n); // ''Hello!'' will only be logged on the first click\n\nconst newListenOnce = (el, evt, fn) =>\n  el.addEventListener(evt, fn, { once: true });\n\nnewListenOnce(document.getElementById(\"my-btn\"), \"click\", () =>\n  console.log(\"Hello!\")\n); // ''Hello!'' will only be logged on the first click\n"}', '{}', '{"original_path": "Vanilla/Logic/Browser/how-can-i-execute-an-event-handler-at-most-once"}'), ('"understanding-event-bubbling-capturing-and-delegation-in-javascript"', '"Logic"', '"vanilla"', '{"demo.css": "div {\r\n  margin: 1rem;\r\n}\r\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\">\n    <link rel=\"stylesheet\" href=\"style.css\"></link>\n    <title>Static Template</title>\n  </head>\n  <body>\n    <h1>Understanding event bubbling, capturing and delegation in JavaScript</h1>\n    <div>\n      Check your log on the console After clicking the button below.\n    </div>\n    <div id=\"btn-container\">\n      <button class=\"btn\">Click me</button>\n    </div>\n    <script src=\"script.js\"></script>\n  </body>\n</html>", "demo.js": "const ancestors = [\r\n  window,\r\n  document,\r\n  document.documentElement,\r\n  document.body,\r\n  document.getElementById(\"btn-container\")\r\n];\r\n\r\n// Target phase\r\ndocument.querySelector(\".btn\").addEventListener(\"click\", (e) => {\r\n  console.log(`Hello from ${e.target}`);\r\n});\r\n\r\n/* Bubble phase */\r\nancestors.forEach((a) => {\r\n  a.addEventListener(\"click\", (e) => {\r\n    console.log(`Hello from ${e.currentTarget}`);\r\n  });\r\n});\r\n\r\n// Capture phase\r\nancestors.forEach((a) => {\r\n  a.addEventListener(\r\n    \"click\",\r\n    (e) => {\r\n      console.log(`Hello from ${e.currentTarget}`);\r\n    },\r\n    true\r\n  );\r\n});\r\n\r\nwindow.addEventListener(\"click\", (e) => {\r\n  if (e.target.className === \"btn\") console.log(\"Hello there!\");\r\n});\r\n", "package.json": "{\n  \"name\": \"understanding-event-bubbling-capturing-and-delegation-in-javascript\",\n  \"version\": \"1.0.0\",\n  \"description\": \"\",\n  \"main\": \"index.html\",\n  \"scripts\": {\n    \"start\": \"serve\",\n    \"build\": \"echo This is a static template, there is no bundler or bundling involved!\"\n  },\n  \"repository\": {\n    \"type\": \"git\",\n    \"url\": \"git+https://github.com/codesandbox-app/static-template.git\"\n  },\n  \"keywords\": [],\n  \"author\": \"Ives van Hoorne\",\n  \"license\": \"MIT\",\n  \"bugs\": {\n    \"url\": \"https://github.com/codesandbox-app/static-template/issues\"\n  },\n  \"homepage\": \"https://github.com/codesandbox-app/static-template#readme\",\n  \"devDependencies\": {\n    \"serve\": \"^11.2.0\"\n  }\n}", "sandbox.config.json": "{\n  \"template\": \"static\"\n}\n"}', '{}', '{"original_path": "Vanilla/Logic/Browser/understanding-event-bubbling-capturing-and-delegation-in-javascript"}'), ('"get-and-set-html-content-inside-an-element-as-a-string"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get and set HTML content inside an element as a string\r\n    </h1>\r\n    <div class=\"greeting\">\r\n      <p>Hello world!</p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get and set the HTML content inside an element as a string.\n */\n\nlet greeting = document.querySelector(\".greeting\");\n\n// Get HTML content\n// returns \"<p>Hello world!</p>\"\nlet html = greeting.innerHTML;\n\n// Set HTML content\n// This replaces what was in there already\ngreeting.innerHTML =\n  ''We can dynamically change the HTML. We can even include HTML elements like <a href=\"#\">this link</a>.'';\n\n// Add HTML to the end of an element''s existing content\ngreeting.innerHTML += \" Add this after what is already there.\";\n\n// Add HTML to the beginning of an element''s existing content\ngreeting.innerHTML = \"We can add this to the beginning. \" + elem.innerHTML;\n\n// You can inject entire elements into other ones, too\ngreeting.innerHTML += \"<p>A new paragraph</p>\";\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/getSet/get-and-set-html-content-inside-an-element-as-a-string"}'), ('"get-and-set-inline-styles-for-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get and set inline wtyles for an element\r\n    </h1>\r\n    <p id=\"sandwich\" style=\"background-color: green; color: white;\">Sandwich</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get and set inline styles for an element.\n */\n\nlet sandwich = document.querySelector(\"#sandwich\");\n\n// Get a style\n// If this style is not set as an inline style directly on the element, it returns an empty string\nlet bgColor = sandwich.style.backgroundColor; // this will return \"green\"\nlet fontWeight = sandwich.style.fontWeight; // this will return \"\"\n\n// Set the background-color style property\nsandwich.style.backgroundColor = \"purple\";\n\n/**\n * You can also get and set a string representation of the entire inline style property\n * on the element itself with the Element.style.cssText property.\n */\n\n// Get the styles on an element\n// returns \"background-color: green; color: white;\"\nlet styles = sandwich.style.cssText;\n\n// Completely replace the inline styles on an element\nsandwich.style.cssText = \"font-size: 2em; font-weight: bold;\";\n\n// Add additional styles\nsandwich.style.cssText += \"color: purple;\";\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/getSet/get-and-set-inline-styles-for-an-element"}'), ('"get-and-set-the-html-content-including-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get and set the HTML content including an element\r\n    </h1>\r\n    <div class=\"greeting\">\r\n      <p>Hello world!</p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get and set the HTML content including an element.\n * This works the same as Element.innerHTML,\n * but includes the element itself when getting and updating HTML content.\n */\n\nlet greeting = document.querySelector(\".greeting\");\n\n// Get HTML content\n// returns \"<div class=\"greeting\"><p>Hello world!</p></div>\"\nlet html = greeting.outerHTML;\n\n// Set HTML content\n// This completely replaces the <div class=\"greeting\"></div> element and all of its content\ngreeting.outerHTML =\n  ''<p class=\"outro\">Goodbye, friend! <a href=\"exit.html\">Click here to leave.</a>'';\n\n// Add HTML after the element (and outside of it)\ngreeting.outerHTML += \" Add this after what is already there.\";\n\n// Add HTML before the element (and outside of it)\ngreeting.outerHTML = \"We can add this to the beginning. \" + greeting.innerHTML;\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/getSet/get-and-set-the-html-content-including-an-element"}'), ('"get-and-set-the-rendered-text-of-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get and set the rendered text of an element\r\n    </h1>\r\n    <div class=\"greeting\">\r\n      <style type=\"text/css\">\r\n        p {\r\n          color: rebeccapurple;\r\n        }\r\n      </style>\r\n      <p hidden>This is not rendered.</p>\r\n      <p>Hello world!</p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get and set the rendered text of an element (and omit the markup).\n * The Element.innerText property returns only rendered text,\n * similar to what a user would be able to select with their cursor or the keyboard when highlighting text.\n * Any HTML elements included in a string when setting content are automatically encoded and rendered as-is.\n */\n\nlet elem = document.querySelector(\".greeting\");\n\n// Get text content\n// returns \"Hello world!\"\nlet text = elem.innerText;\n\n// Set text content\n// This completely replaces whats there, including any HTML elements\nelem.innerText = \"We can dynamically change the content.\";\n\n// Add text to the end of an element''s existing content\nelem.innerText += \" Add this after what is already there.\";\n\n// Add text to the beginning of an element''s existing content\nelem.innerText = \"We can add this to the beginning. \" + elem.innerText;\n\n// HTML elements are automatically encoded and rendered as-is\nelem.innerText = \"<p>See you later!</p>\";\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/getSet/get-and-set-the-rendered-text-of-an-element"}'), ('"get-and-set-the-text-of-an-element-as-a-string"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get and set the text of an element as a string\r\n    </h1>\r\n    <div class=\"greeting\">\r\n      <style type=\"text/css\">\r\n        p {\r\n          color: rebeccapurple;\r\n        }\r\n      </style>\r\n      <p hidden>This is not rendered.</p>\r\n      <p>Hello world!</p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get and set the text of an element (and omit the markup) as a string.\n * The Node.textContent property gets all of the text content,\n * including CSS properties inside of a style element and hidden UI elements.\n * Any HTML elements included in a string when setting content\n * with the Node.textContent property are automatically encoded and rendered as-is.\n */\n\nlet greeting = document.querySelector(\".greeting\");\n\n// Get text content\n// returns \"p {color: rebeccapurple;} This is not rendered. Hello world!\"\nlet text = greeting.textContent;\n\n// Set text content\n// This completely replaces whats there, including any HTML elements\ngreeting.textContent = \"We can dynamically change the content.\";\n\n// Add text to the end of an element''s existing content\ngreeting.textContent += \" Add this after what is already there.\";\n\n// Add text to the beginning of an element''s existing content\ngreeting.textContent =\n  \"We can add this to the beginning. \" + greeting.textContent;\n\n// HTML elements are automatically encoded and rendered as-is\ngreeting.textContent = \"<p>See you later!</p>\";\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/getSet/get-and-set-the-text-of-an-element-as-a-string"}'), ('"append-elements-or-strings"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Append elements or strings\r\n    </h1>\r\n    <ul id=\"list\">\r\n      <li>Item 1</li>\r\n      <li>Item 2</li>\r\n      <li>Item 3</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Insert one or more elements or strings\n * at the end of a set elements inside a shared parent.\n * Call the Element.append() method on the target node,\n * and pass in one or more new elements or strings as arguments.\n */\n\n// Create a new element\nlet li = document.createElement(\"li\");\nli.textContent = \"I am new here.\";\n\n// Create another new element\nlet liToo = document.createElement(\"li\");\nliToo.textContent = `I''m new, too!`;\n\n// Get the parent node\nlet list = document.querySelector(\"#list\");\n\n// Insert the new node after the last element in the parent node\n// ...<li>Item 3</li><li>I am new here.</li>\nlist.append(li);\n\n// You can inject more than one item by passing in multiple arguments\n// ...<li>Item 3</li><li>I am new here.</li><li>I''m new, too!</li>\nlist.append(li, liToo);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/append-elements-or-strings"}'), ('"create-a-copy-of-a-node"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div id=\"app\" class=\"background\" data-app>\r\n      <h1>Hello, world!</h1>\r\n      <p>How are you today?</p>\r\n      Nice to see you again.\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Create a copy of a node. Call on the node to clone.\n * If you want all of a node\u2019s child nodes to also be copied,\n * pass in true as an argument.\n */\n\n// returns <div id=\"app\" class=\"background\" data-app>\nlet app = document.querySelector(\"#app\");\n\n// Create a shallow clone\n// returns <div id=\"app\" class=\"background\" data-app></div> as an empty node\nlet clone = app.cloneNode();\n\n// Create a deep clone\n// returns <div id=\"app\" class=\"background\" data-app></div> with the h1, p, and text nodes\nlet deepClone = app.cloneNode(true);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/create-a-copy-of-a-node"}'), ('"insert-elements-and-string-after-another-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div id=\"app\">Good morning</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Insert elements and strings after another element.\n * Call the Node.after() method on the node you want to insert after,\n * and pass in one or more new elements or strings as arguments.\n */\n\n// Create a new element\nlet p = document.createElement(\"p\");\np.textContent = \"Hello!\";\n\n// Get the target node\nlet app = document.querySelector(\"#app\");\n\n// Insert the new node after the target node\n// <div id=\"app\">Good morning</div><p>Hello!</p>\napp.after(p);\n\n// You can inject more than one item by passing in multiple arguments\n// <div id=\"app\">Good morning</div><p>Hello!</p>What''s poppin''\napp.after(p, `What''s poppin?`);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/insert-elements-and-string-after-another-element"}'), ('"insert-elements-and-string-before-another-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Insert elements and string before another element\r\n    </h1>\r\n    <div id=\"app\">Good evening</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Insert elements and strings before another element.\n * Call the Node.before() method on the node you want to insert before,\n * and pass in one or more new elements or strings as arguments.\n */\n\n// Create a new element\nlet p = document.createElement(\"p\");\np.textContent = \"Hello!\";\n\n// Get the target node\nlet app = document.querySelector(\"#app\");\n\n// Insert the new node before the target node\n// <p>Hello!</p><div id=\"app\">Good evening</div>\napp.before(p);\n\n// You can inject more than one item by passing in multiple arguments\n// <p>Hello!</p>What''s poppin''<div id=\"app\">Good evening</div>\napp.before(p, `What''s poppin?`);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/insert-elements-and-string-before-another-element"}'), ('"prepend-elements-or-strings"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Prepend elements or strings\r\n    </h1>\r\n    <ul id=\"list\">\r\n      <li>Item 1</li>\r\n      <li>Item 2</li>\r\n      <li>Item 3</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Insert one or more elements or strings at the beginning of a set elements inside a shared parent.\n *  Call the Element.prepend() method on the target node,\n * and pass in one or more new elements or strings as arguments.\n */\n\n// Create a new element\nlet li = document.createElement(\"li\");\nli.textContent = \"I am new here.\";\n\n// Create another new element\nlet liToo = document.createElement(\"li\");\nliToo.textContent = `I''m new, too!`;\n\n// Get the parent node\nlet list = document.querySelector(\"#list\");\n\n// Insert the new node before the first element in the parent node\n// <li>I am new here.</li><li>Item 1</li>...\nlist.prepend(li);\n\n// You can inject more than one item by passing in multiple arguments\n// <li>I am new here.</li><li>I''m new, too!</li><li>Item 1</li>...\nlist.prepend(li, liToo);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/prepend-elements-or-strings"}'), ('"remove-an-element-from-the-dom"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>Hello, world!</h1>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Remove an element from the DOM.\n *\n * Call the Node.remove() method on the element you want to remove.\n */\nlet h1 = document.querySelector(\"h1\");\nh1.remove();\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/remove-an-element-from-the-dom"}'), ('"replace-an-element-with-another"', '"Logic"', '"vanilla"', '{"Replace-an-element-with-another.html": "<h1>Good evening</h1>\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>Good evening</h1>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Replace an element (and all of its HTML elements and content) with another.\n * Call the Node.replaceWith() method on the target node,\n * and pass in one or more elements or strings as arguments.\n */\n\n// Get the target element\nlet h1 = document.querySelector(\"h1\");\n\n// Create a new element\nlet p = document.createElement(\"p\");\np.textContent = \"Good morning\";\n\n// Replace the target with the new element\n// <p>Good morning</p>\nh1.replaceWith(p);\n\n// You can replace it with more than one item by passing in multiple arguments\n// <p>Good morning</p>How are you today?\nh1.replaceWith(p, \"How are you today?\");\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/manipulation/replace-an-element-with-another"}'), ('"get-the-closest-parent-up-the-dom-tree"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the closest parent up the DOM tree\r\n    </h1>\r\n    <main>\r\n      <div class=\"hero\">\r\n        <div id=\"app\">\r\n          <h1 data-sandwich>Hello, world!</h1>\r\n        </div>\r\n      </div>\r\n    </main>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the closest parent up the DOM tree that matches against a selector.\n * The Element.closest() method starts with the element itself.\n * You can start with the first parent element by pairing it with the Node.parentNode property.\n */\nlet h1 = document.querySelector(\"h1\");\n\n// returns the .hero element\nlet hero = h1.closest(\".hero\");\n\n// returns the h1 element itself\nlet sandwich = h1.closest(\"[data-sandwich]\");\n\n// Start with the element''s parent\n// returns null\nlet sandwich2 = h1.parentNode.closest(\"[data-sandwich]\");\n\nconsole.warn(hero);\nconsole.warn(sandwich);\nconsole.warn(sandwich2);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-closest-parent-up-the-dom-tree"}'), ('"get-the-first-and-last-child-nodes-of-a-parent-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the first and last child nodes of a parent element\r\n    </h1>\r\n    <ul>\r\n      <!-- The gray wizard -->\r\n      <li>Gandalf</li>\r\n      <li>Radagast</li>\r\n      <li>Hermione</li>\r\n      <!-- The surprise hero -->\r\n      <li>Neville</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the first and last child nodes of a parent element,\n * including nodes that aren\u2019t elements (such as comments and text fragments).\n */\n\nlet wizards = document.querySelector(\"ul\");\n\n// returns the comment node <!-- The gray wizard -->\nlet firstDescendant = wizards.firstChild;\n\n// returns <li>Neville</li>\nlet lastDescendant = wizards.lastChild;\n\nconsole.warn(firstDescendant);\nconsole.warn(lastDescendant);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-first-and-last-child-nodes-of-a-parent-element"}'), ('"get-the-immediate-descendants-of-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the Immediate descendants of an element\r\n    </h1>\r\n    <ul>\r\n      <!-- The gray wizard -->\r\n      <li>Gandalf</li>\r\n      <li>Radagast</li>\r\n      <li>Hermione</li>\r\n      <!-- The surprise hero -->\r\n      <li>Neville</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the immediate descendants of an element,\n * including text fragments and other non-element nodes.\n */\n\nlet wizards = document.querySelector(\"ul\");\n\n// returns all nodes, including the comments\nlet descendants = wizards.childNodes;\n\nconsole.warn(descendants);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-immediate-descendants-of-an-element"}'), ('"get-the-next-and-previous-sibling-element-of-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the next and previous sibling element of an element\r\n    </h1>\r\n    <ul>\r\n      <!-- The gray wizard -->\r\n      <li>Gandalf</li>\r\n      <li>Radagast</li>\r\n      <li id=\"hermione\">Hermione</li>\r\n      <!-- The surprise hero -->\r\n      <li>Neville</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the next and previous sibling element of an element.\n */\n\nlet hermione = document.querySelector(\"#hermione\");\n\n// returns <li>Neville</li>\nlet next = hermione.nextElementSibling;\n\n// returns <li>Radagast</li>\nlet previous = hermione.previousElementSibling;\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-next-and-previous-sibling-element-of-an-element"}');